source_sections.text:
{
  "day": "1",
  "heading": "Reach the Indiahikes Jungle Line Campus at Manali",
  "sub_heading": "Pick Up Point and Time: Beas Bridge, Manali at 3 PM",
  "details": "Pick-up will be arranged from Beas Bridge, Manali to Indiahikes Jungle Line Campus at 3 pm. Collect your rentals, sort out the cloakroom and attend a detailed trek briefing."
}

{
  "day": "2",
  "heading": "Drive from Manali to Kibber",
  "sub_heading": "Drive Distance: 180 km | Drive Duration: 7 hrs | Altitude Gain: 6,000 ft to 13,500 ft",
  "details": "Embark on a scenic drive to Kibber, crossing the iconic Atal Tunnel and passing through the picturesque high altitude landscape of Spiti. The route winds alongside the majestic Chenab River, cutting through the stark and stunning cold desert landscapes of the Lahaul-Spiti region.\nThe cost is Rs. 2400 (additional 5% GST) per trekker one-way from Manali to Kibber. The pick-up from Beas Bridge is included in this cost. These are non-AC vehicles. Please pre-book your transport through the dashboard before your trek."
}

{
  "day": "3",
  "heading": "Acclimatisation Day at Kibber",
  "sub_heading": "",
  "details": "Kibber is a beautiful little hamlet at the heart of Spiti. Take a short day-hike, visit the Chicham Bridge or just delve into the local culture of this remote Himalayan region. This day is meant for you to relax and allow your body to acclimatise to the high altitude. So make sure that you hydrate well and do not exert yourself too much."
}

{
  "day": "4",
  "heading": "Trek to Kanamo Basecamp",
  "sub_heading": "Trek Distance: 5.5 km | Trek Duration: 6 hrs | Altitude Gain: 13,500 ft to 15,850 ft",
  "details": ""
}

{
  "day": "5",
  "heading": "Acclimatisation Day at Kanamo Basecamp",
  "sub_heading": "",
  "details": "Use the day to rest and acclimatise to the high altitude environment. The Technical Team will also be conducting sessions to prepare you fully for the strenuous summit push on the next day."
}

{
  "day": "6",
  "heading": "Trek to Kanamo Peak. Back to Kanamo Basecamp.",
  "sub_heading": "Trek Distance: 11 km | Trek Duration: 12 hrs | Altitude Change: 15,850 ft to 19,500 ft",
  "details": "Summit push will start early, in pitch darkness to be able to reach the summit by Sunrise. After spending some time there, return to basecamp."
}

{
  "day": "7",
  "heading": "Trek from Kanamo Basecamp to Kibber. Drive to Manali.",
  "sub_heading": "Trek Distance: 5.5 km | Trek Duration: 3 hrs | Altitude Loss: 15,850 ft to 13,500 ft\nDrive Distance: 180 km | Drive Duration: 7 hrs | Drop-off Time: 8 PM | Drop-Off Point: Beas Bridge, Manali",
  "details": "Trek to the roadhead at Kibber and drive back to Manali. Return your rentals and collect your cloakroom luggage from Indiahikes Jungle Line Campus before heading to Beas Bridge, where you’ll be dropped off.\nThe cost of transfer is Rs. 2400 (additional 5% GST) per trekker one-way from Kibber to Manali. These are non-AC vehicles. Please pre-book your transport through the dashboard before your trek."
}
